package kr.gampa.battlegrounds.action; public final class TimedAction {private final long required;private final double radius;private long elapsed;private ActionStatus status=ActionStatus.RUNNING;public TimedAction(long required,double radius){if(required<=0||radius<0)throw new IllegalArgumentException();this.required=required;this.radius=radius;}public ActionStatus tick(long ticks){if(status==ActionStatus.RUNNING){elapsed+=Math.max(0,ticks);if(elapsed>=required)status=ActionStatus.COMPLETED;}return status;}public ActionStatus move(double distance){if(status==ActionStatus.RUNNING&&distance>radius)status=ActionStatus.CANCELLED;return status;}public ActionStatus damage(){if(status==ActionStatus.RUNNING)status=ActionStatus.CANCELLED;return status;}public ActionStatus weaponSwitch(){return damage();}public ActionStatus cancel(){return damage();}public ActionStatus status(){return status;}public double progress(){return Math.min(1d,(double)elapsed/required);}}